code.C:
#include <stdio.h>
int findMissingNumber(int* nums, int numsSize) {
   int n = numsSize + 1;
   int expectedSum = (n * (n + 1)) / 2;
   int actualSum = 0;
   for (int i = 0; i < numsSize; i++) {
      actualSum += nums[i];
   }
   return expectedSum - actualSum;
}

code.C++:
#include <iostream>
#include <vector>
int findMissingNumber(std::vector<int>& nums) {
   int n = nums.size() + 1;
   int expectedSum = (n * (n + 1)) / 2;
   int actualSum = 0;
   for (int num : nums) {
      actualSum += num;
   }
   return expectedSum - actualSum;
}

